// Get http response input from AI
const positions = $input.first().json.response;

try {
  // Process positions to calculate percentages
  if (positions && Array.isArray(positions)) {
    // Calculate total strategy value from positions
    let strategyValue = 0;
    for (const position of positions) {
      const amount = parseFloat(position.amount);
      const isAsset = amount >= 0;
      const currentPrice = parseFloat(isAsset ? position.bid : position.ask);
      strategyValue += amount * currentPrice;
    }

    if(strategyValue <= 0) throw new Error('Strategy value must be greater than 0.');

    // Calculate percentage for each position
    const filteredPositions = positions.filter((position) => `${position.stock}:${position.provider}`.toUpperCase() !== 'USD:ALPHAINSIDER');
    const parsedPositions = filteredPositions.map((position) => {
      const amount = parseFloat(position.amount);
      const isAsset = amount >= 0;
      const currentPrice = parseFloat(isAsset ? position.bid : position.ask);
      const positionPercent = Math.abs((amount * currentPrice) / strategyValue);

      return {
        stock_id: position.stock_id,
        stock: position.stock,
        exchange: position.exchange,
        action: (isAsset ? 'long' : 'short'),
        percent: positionPercent
      };
    });

    //return parsed positions
    return {positions: parsedPositions};
  }

  return {positions: []};

} catch (error) {
  throw {
    error: 'Failed to fetch positions',
    message: error.message,
    input: positions
  };
}

