{
  "type": "object",
  "properties": {
    "action": {
      "type": "string",
      "enum": ["trade", "post", "none"],
      "description": "The type of action to take: 'trade' = make a trade with allocations, 'post' = make a post to audience with no trade intention, 'none' = direct conversation with agent (Q&A or unrelated input)"
    },
    "allocations": {
      "type": "array",
      "description": "Array of stock allocation objects. Only populate when action = 'trade'. Empty array otherwise.",
      "items": {
        "type": "object",
        "properties": {
          "action": {
            "type": "string",
            "description": "Trading action: long, short, or close"
          },
          "stock_id": {
            "type": "string",
            "description": "Stock identifier or ticker symbol writen as \"SYMBOL:EXCHANGE\" or stock_id from AlphaInsider"
          },
          "percent": {
            "type": "number",
            "description": "Allocation percentage as a decimal number. 0 <= percent <= 2."
          }
        },
        "required": ["action", "stock_id", "percent"]
      }
    },
    "post": {
      "type": "object",
      "description": "Only populated when action = 'post'. Contains the user's message to their audience.",
      "properties": {
        "description": {
          "type": "string",
          "description": "The exact message made by the user that is talking to their audience"
        },
        "url": {
          "type": "string",
          "description": "If the user input text has a main URL in it (if multiple urls, find the most important one), separate this url and submit it to this field. Optional."
        }
      },
      "required": ["description"]
    },
    "message": {
      "type": "string",
      "description": "Direct message back to the user about what was done. For trades: describe what positions have changed and current positions. For posts: simple confirmation of the post submitted. For none: answer questions or explain why no action was taken."
    }
  },
  "required": ["action", "allocations", "message"]
}

